package main

import (
	"flag"
	"fmt"
	"os"
	"time"

	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/router"
)

func main() {
	klog.InitFlags(nil)
	flag.Parse()

	port := 8080
	if p := os.Getenv("ROUTER_PORT"); p != "" {
		fmt.Sscanf(p, "%d", &port)
	}

	enableTLS := os.Getenv("ENABLE_TLS") == "true"
	tlsCertFile := os.Getenv("TLS_CERT_FILE")
	tlsKeyFile := os.Getenv("TLS_KEY_FILE")

	maxConcurrentRequests := 1000
	if m := os.Getenv("MAX_CONCURRENT_REQUESTS"); m != "" {
		fmt.Sscanf(m, "%d", &maxConcurrentRequests)
	}

	config := &router.ServerConfig{
		Port:                  port,
		WorkloadManagerURL:    os.Getenv("WORKLOAD_MANAGER_URL"),
		MaxConcurrentRequests: maxConcurrentRequests,
		EnableTLS:             enableTLS,
		TLSCertFile:           tlsCertFile,
		TLSKeyFile:            tlsKeyFile,
	}

	server, err := router.NewServer(config)
	if err != nil {
		klog.Fatalf("Failed to create router server: %v", err)
	}

	klog.Infof("Starting Router on port %d", port)
	if err := server.Start(); err != nil {
		klog.Fatalf("Server failed: %v", err)
	}
}

