package router

import (
	"context"
	"fmt"
	"net"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"os/signal"
	"strings"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	DefaultMaxConcurrentRequests = 1000
)

type Server struct {
	config         *ServerConfig
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager *SessionManager
	storeClient    store.Store
	httpTransport  *http.Transport
	jwtManager     *JWTManager
	semaphore      chan struct{}
}

func NewServer(config *ServerConfig) (*Server, error) {
	if config.WorkloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	if config.MaxConcurrentRequests <= 0 {
		config.MaxConcurrentRequests = DefaultMaxConcurrentRequests
	}

	ginMode := gin.ReleaseMode
	if os.Getenv("DEBUG") == "true" {
		ginMode = gin.DebugMode
	}
	gin.SetMode(ginMode)

	engine := gin.New()

	storeClient := store.Storage()

	sessionManager, err := NewSessionManager(config.WorkloadManagerURL)
	if err != nil {
		return nil, err
	}

	jwtManager := NewJWTManager()
	if err := jwtManager.TryStoreOrLoadJWTKeySecret(""); err != nil {
		return nil, fmt.Errorf("failed to initialize JWT manager: %w", err)
	}

	httpTransport := &http.Transport{
		IdleConnTimeout:    0,
		DisableCompression: false,
	}

	s := &Server{
		config:         config,
		engine:         engine,
		sessionManager: sessionManager,
		storeClient:    storeClient,
		httpTransport:  httpTransport,
		jwtManager:     jwtManager,
		semaphore:      make(chan struct{}, config.MaxConcurrentRequests),
	}

	s.registerRoutes()

	return s, nil
}

func (s *Server) registerRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1 := s.engine.Group("/v1")
	v1.Use(gin.Logger(), gin.Recovery(), s.concurrencyLimitMiddleware)

	v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status": "alive",
	})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "ready",
	})
}

func (s *Server) concurrencyLimitMiddleware(c *gin.Context) {
	select {
	case s.semaphore <- struct{}{}:
		defer func() { <-s.semaphore }()
		c.Next()
	default:
		c.JSON(http.StatusTooManyRequests, gin.H{
			"error": "server overloaded, please try again later",
			"code":  "SERVER_OVERLOADED",
		})
		c.Abort()
	}
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	s.handleInvoke(c, types.AgentRuntimeKind)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	s.handleInvoke(c, types.CodeInterpreterKind)
}

func (s *Server) handleInvoke(c *gin.Context, kind string) {
	ctx := c.Request.Context()

	sessionID := c.GetHeader(SessionHeader)

	var sandbox *types.SandboxInfo
	var err error

	if sessionID == "" {
		namespace := c.Param("namespace")
		name := c.Param("name")

		sandbox, err = s.sessionManager.CreateSandbox(ctx, kind, name, namespace)
		if err != nil {
			if api.IsSandboxTemplateNotFoundError(err) {
				c.JSON(http.StatusNotFound, gin.H{
					"error": err.Error(),
				})
				return
			}
			c.JSON(http.StatusInternalServerError, gin.H{
				"error": "internal server error",
			})
			return
		}

		sessionID = sandbox.SessionID

		if err := s.storeClient.UpdateSessionLastActivity(ctx, sessionID, time.Now()); err != nil {
			klog.V(4).Infof("Warning: failed to update last activity: %v", err)
		}
	} else {
		sandbox, err = s.sessionManager.GetSandboxBySession(ctx, sessionID, kind)
		if err != nil {
			if api.IsSessionNotFoundError(err) {
				c.JSON(http.StatusNotFound, gin.H{
					"error": err.Error(),
				})
				return
			}
			c.JSON(http.StatusInternalServerError, gin.H{
				"error": "internal server error",
			})
			return
		}

		if err := s.storeClient.UpdateSessionLastActivity(ctx, sessionID, time.Now()); err != nil {
			klog.V(4).Infof("Warning: failed to update last activity: %v", err)
		}
	}

	s.forwardToSandbox(c, sandbox, sessionID)

	if err := s.storeClient.UpdateSessionLastActivity(ctx, sessionID, time.Now()); err != nil {
		klog.V(4).Infof("Warning: failed to update last activity after forward: %v", err)
	}
}

func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, sessionID string) {
	if len(sandbox.EntryPoints) == 0 {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "no entry point found for sandbox",
		})
		return
	}

	path := c.Param("path")
	if path != "" && !strings.HasPrefix(path, "/") {
		path = "/" + path
	}

	var targetEntryPoint *types.SandboxEntryPoint
	for _, ep := range sandbox.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, ep.Path) {
			targetEntryPoint = &ep
			break
		}
	}

	if targetEntryPoint == nil {
		targetEntryPoint = &sandbox.EntryPoints[0]
	}

	protocol := strings.ToLower(targetEntryPoint.Protocol)
	endpoint := targetEntryPoint.Endpoint

	if !strings.HasPrefix(endpoint, "http://") && !strings.HasPrefix(endpoint, "https://") {
		if protocol == "" {
			protocol = "http"
		}
		endpoint = protocol + "://" + endpoint
	}

	targetURL, err := url.Parse(endpoint)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "invalid upstream URL",
		})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)

		req.URL.Path = path
		if req.URL.RawPath != "" {
			req.URL.RawPath = ""
		}

		req.Host = targetURL.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		clientIP := c.ClientIP()
		existingForwarded := req.Header.Get("X-Forwarded-For")
		if existingForwarded != "" {
			req.Header.Set("X-Forwarded-For", existingForwarded+", "+clientIP)
		} else {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(sessionID, sandbox.Kind)
			if err != nil {
				klog.Errorf("Failed to generate JWT: %v", err)
				c.JSON(http.StatusInternalServerError, gin.H{
					"error": "failed to sign request",
					"code":  "JWT_SIGNING_FAILED",
				})
				c.Abort()
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		errMsg := err.Error()
		if strings.Contains(errMsg, "connection refused") {
			c.JSON(http.StatusBadGateway, gin.H{
				"error": "sandbox unreachable",
			})
			return
		}
		if strings.Contains(errMsg, "timeout") {
			c.JSON(http.StatusGatewayTimeout, gin.H{
				"error": "sandbox timeout",
			})
			return
		}
		c.JSON(http.StatusBadGateway, gin.H{
			"error": "sandbox unreachable",
		})
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

func (s *Server) Start() error {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	addr := fmt.Sprintf(":%d", s.config.Port)
	listener, err := net.Listen("tcp", addr)
	if err != nil {
		return err
	}

	if err := s.storeClient.Ping(ctx); err != nil {
		return fmt.Errorf("store ping failed: %w", err)
	}

	s.httpServer = &http.Server{
		Addr:        addr,
		Handler:     h2c.NewHandler(s.engine, &http2.Server{}),
		ReadTimeout: 30 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-sigChan
		klog.Info("Received shutdown signal, shutting down gracefully...")
		shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 10*time.Second)
		defer shutdownCancel()

		if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
			klog.Errorf("HTTP server shutdown error: %v", err)
		}

		s.storeClient.Close()
		cancel()
	}()

	klog.Infof("Router starting on %s", addr)

	if s.config.EnableTLS {
		if s.config.TLSCertFile == "" || s.config.TLSKeyFile == "" {
			return fmt.Errorf("TLS is enabled but cert/key not provided")
		}
		return s.httpServer.ServeTLS(listener, s.config.TLSCertFile, s.config.TLSKeyFile)
	}

	return s.httpServer.Serve(listener)
}

