package workloadmanager

import (
	"container/list"
	"context"
	"fmt"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	authenticationv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
)

const (
	TokenCacheCapacity    = 1000
	TokenCacheEntryTTL    = 5 * time.Minute
	UserClientCachePrefix = "userclient:"
)

type TokenCacheEntry struct {
	Username      string
	SANamespace   string
	SAName        string
	Authenticated bool
	ExpiresAt     time.Time
}

type LRUTokenCache struct {
	mu       sync.RWMutex
	cache    map[string]*list.Element
	list     *list.List
	capacity int
}

type cacheItem struct {
	key   string
	entry *TokenCacheEntry
}

func NewLRUTokenCache(capacity int) *LRUTokenCache {
	return &LRUTokenCache{
		cache:    make(map[string]*list.Element),
		list:     list.New(),
		capacity: capacity,
	}
}

func (c *LRUTokenCache) Get(key string) (*TokenCacheEntry, bool) {
	c.mu.RLock()
	elem, ok := c.cache[key]
	c.mu.RUnlock()

	if !ok {
		return nil, false
	}

	c.mu.Lock()
	defer c.mu.Unlock()

	c.list.MoveToFront(elem)
	return elem.Value.(*cacheItem).entry, true
}

func (c *LRUTokenCache) Set(key string, entry *TokenCacheEntry) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, ok := c.cache[key]; ok {
		c.list.MoveToFront(elem)
		item := elem.Value.(*cacheItem)
		item.entry = entry
		return
	}

	elem := c.list.PushFront(&cacheItem{key: key, entry: entry})
	c.cache[key] = elem

	if c.list.Len() > c.capacity {
		oldest := c.list.Back()
		if oldest != nil {
			item := oldest.Value.(*cacheItem)
			delete(c.cache, item.key)
			c.list.Remove(oldest)
		}
	}
}

func (c *LRUTokenCache) Delete(key string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	if elem, ok := c.cache[key]; ok {
		delete(c.cache, key)
		c.list.Remove(elem)
	}
}

type AuthMiddleware struct {
	clientset *kubernetes.Clientset
	cache     *LRUTokenCache
}

