)

type TokenCacheEntry struct {
	Username      string
	SANamespace   string
	SAName        string
	Authenticated bool
	ExpiresAt     time.Time
}

type AuthMiddleware struct {
	clientset *kubernetes.Clientset
	cache     sync.Map
}

func newAuthMiddleware() (*AuthMiddleware, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		return nil, fmt.Errorf("failed to get in-cluster config: %w", err)
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create clientset: %w", err)
	}

	return &AuthMiddleware{
		clientset: clientset,
	}, nil
}

func authMiddleware(c *gin.Context) {
	authHeader := c.GetHeader("Authorization")
	if authHeader == "" {
		c.JSON(http.StatusUnauthorized, gin.H{
			"message": "Missing authorization header",
		})
		c.Abort()
		return
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || parts[0] != "Bearer" {
		c.JSON(http.StatusUnauthorized, gin.H{
			"message": "Invalid authorization header format",
		})
		c.Abort()
		return
	}

	token := parts[1]

	am, ok := c.Get("authMiddleware")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{
			"message": "Auth middleware not configured",
		})
		c.Abort()
		return
	}

	authMid := am.(*AuthMiddleware)

	username, saNamespace, saName, err := authMid.validateToken(c.Request.Context(), token)
	if err != nil {
		c.JSON(http.StatusUnauthorized, gin.H{
			"message": fmt.Sprintf("Token validation failed: %v", err),
		})
		c.Abort()
		return
	}

	c.Set("token", token)
	c.Set("username", username)
	c.Set("serviceAccountNamespace", saNamespace)
	c.Set("serviceAccountName", saName)

	c.Next()
}

func (am *AuthMiddleware) validateToken(ctx context.Context, token string) (username, saNamespace, saName string, err error) {
	if entry, ok := am.cache.Load(token); ok {
		cacheEntry := entry.(*TokenCacheEntry)
		if time.Now().Before(cacheEntry.ExpiresAt) {
			if !cacheEntry.Authenticated {
				return "", "", "", fmt.Errorf("token not authenticated")
			}
			return cacheEntry.Username, cacheEntry.SANamespace, cacheEntry.SAName, nil
		}
		am.cache.Delete(token)
	}

	tokenReview := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := am.clientset.AuthenticationV1().TokenReviews().Create(ctx, tokenReview, metav1.CreateOptions{})
	if err != nil {
		return "", "", "", fmt.Errorf("token review failed: %w", err)
	}

	if !result.Status.Authenticated {
		am.cache.Store(token, &TokenCacheEntry{
			Authenticated: false,
			ExpiresAt:     time.Now().Add(5 * time.Minute),
		})
		return "", "", "", fmt.Errorf("token not authenticated")
	}

	username = result.Status.User.Username

	parts := strings.Split(username, ":")
	if len(parts) == 4 && parts[0] == "system" && parts[1] == "serviceaccount" {
		saNamespace = parts[2]
		saName = parts[3]
	}

	cacheEntry := &TokenCacheEntry{
		Username:      username,
		SANamespace:   saNamespace,
		SAName:        saName,
		Authenticated: true,
		ExpiresAt:     time.Now().Add(5 * time.Minute),
	}
	am.cache.Store(token, cacheEntry)

	klog.V(4).Infof("Token validated for user: %s", username)

	return username, saNamespace, saName, nil
}

func getOrCreateUserClient(ctx context.Context, token, namespace, serviceAccountName string) (kubernetes.Interface, error) {
	config := &rest.Config{
		Host:        os.Getenv("KUBERNETES_SERVICE_HOST"),
		BearerToken: token,
		TLSClientConfig: rest.TLSClientConfig{
			Insecure: false,
		},
	}

	return kubernetes.NewForConfig(config)
}

func extractClientFromContext(c *gin.Context) (kubernetes.Interface, error) {
	token, exists := c.Get("token")
	if !exists {
		return nil, api.ErrPublicKeyMissing
	}

	namespace, _ := c.Get("serviceAccountNamespace")
	saName, _ := c.Get("serviceAccountName")

	return getOrCreateUserClient(c.Request.Context(), token.(string), namespace.(string), saName.(string))
}

